import{_ as a,c as o,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Plataformas e Integraciones: Configuración de IA Multi-Modelo","description":"Aprende a configurar y gestionar múltiples plataformas de IA (Anthropic, OpenAI, Google, Copilot), domina los mecanismos de conmutación automática y selección inteligente de modelos.","frontmatter":{"title":"Plataformas e Integraciones: Configuración de IA Multi-Modelo","sidebarTitle":"Conecta Tus Cuentas de IA","subtitle":"Plataformas e Integraciones: Configuración de IA Multi-Modelo","description":"Aprende a configurar y gestionar múltiples plataformas de IA (Anthropic, OpenAI, Google, Copilot), domina los mecanismos de conmutación automática y selección inteligente de modelos.","order":40},"headers":[],"relativePath":"es/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"es/code-yeongyu/oh-my-opencode/platforms/index.md"}'),r={name:"es/code-yeongyu/oh-my-opencode/platforms/index.md"};function n(t,e,l,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="plataformas-e-integraciones" tabindex="-1">Plataformas e Integraciones <a class="header-anchor" href="#plataformas-e-integraciones" aria-label="Permalink to &quot;Plataformas e Integraciones&quot;">​</a></h1><p>Este capítulo presenta cómo configurar y gestionar múltiples Proveedores de IA (Anthropic, OpenAI, Google, GitHub Copilot, etc.), así como el mecanismo de conmutación automática multi-modelo de oh-my-opencode.</p><p>Al completar este capítulo, dominarás cómo habilitar al sistema para seleccionar inteligentemente el modelo de IA más adecuado según el tipo de tarea y los modelos disponibles, construyendo flujos de trabajo de orquestación multi-modelo eficientes y confiables.</p><h2 id="que-cubre-este-capitulo" tabindex="-1">Qué Cubre Este Capítulo <a class="header-anchor" href="#que-cubre-este-capitulo" aria-label="Permalink to &quot;Qué Cubre Este Capítulo&quot;">​</a></h2><p>Este capítulo se divide en dos partes:</p><h3 id="_1-configuracion-de-proveedores" tabindex="-1">1. <a href="./provider-setup/">Configuración de Proveedores</a> <a class="header-anchor" href="#_1-configuracion-de-proveedores" aria-label="Permalink to &quot;1. [Configuración de Proveedores](provider-setup/)&quot;">​</a></h3><p>Aprende a configurar varios Proveedores de IA, incluyendo:</p><ul><li>Anthropic Claude (primera elección del orquestador principal)</li><li>OpenAI ChatGPT (especializado en revisión de arquitectura)</li><li>Google Gemini (análisis de frontend y medios)</li><li>GitHub Copilot (Proveedor de respaldo)</li><li>Z.ai Coding Plan y OpenCode Zen (servicios opcionales)</li></ul><p><strong>Lo Que Aprenderás</strong>:</p><ul><li>✅ Configurar 6 Proveedores de IA principales</li><li>✅ Usar el instalador interactivo para configuración rápida</li><li>✅ Especificar los modelos más adecuados para diferentes agentes</li><li>✅ Usar el comando <code>doctor</code> para diagnosticar problemas de configuración</li></ul><p><strong>Tiempo Estimado</strong>: 25-30 minutos</p><h3 id="_2-estrategia-multi-modelo" tabindex="-1">2. <a href="./model-resolution/">Estrategia Multi-Modelo</a> <a class="header-anchor" href="#_2-estrategia-multi-modelo" aria-label="Permalink to &quot;2. [Estrategia Multi-Modelo](model-resolution/)&quot;">​</a></h3><p>Profundiza en el mecanismo de prioridad de tres pasos del sistema de resolución de modelos:</p><ul><li>Anulación del usuario (control preciso)</li><li>Conmutación de Proveedores (tolerancia a fallos automática)</li><li>Predeterminado del sistema (solución de respaldo)</li></ul><p><strong>Lo Que Aprenderás</strong>:</p><ul><li>✅ Comprender el flujo de trabajo completo de resolución de modelos</li><li>✅ Especificar manualmente modelos según los requisitos de la tarea</li><li>✅ Aprovechar la conmutación de Proveedores para mejorar la robustez del sistema</li><li>✅ Diagnosticar y resolver problemas de resolución de modelos</li></ul><p><strong>Tiempo Estimado</strong>: 30-35 minutos</p><h2 id="ruta-de-aprendizaje-recomendada" tabindex="-1">Ruta de Aprendizaje Recomendada <a class="header-anchor" href="#ruta-de-aprendizaje-recomendada" aria-label="Permalink to &quot;Ruta de Aprendizaje Recomendada&quot;">​</a></h2><p>Recomendamos seguir este orden al estudiar este capítulo:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Instalación Completa] --&gt; B[Configuración de Proveedores]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Estrategia Multi-Modelo]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Funcionalidades Avanzadas]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>¿Por qué este orden?</strong></p><ol><li><strong>Configura primero, comprende después</strong>: Primero aprende a configurar cada Proveedor, luego comprende el mecanismo de resolución subyacente</li><li><strong>De simple a complejo</strong>: La configuración de Proveedores son operaciones básicas, la estrategia multi-modelo es un concepto avanzado</li><li><strong>La práctica valida la teoría</strong>: Después de configurar los Proveedores, puedes usar el comando <code>doctor</code> para verificar la efectividad de la estrategia multi-modelo</li></ol><div class="tip custom-block"><p class="custom-block-title">Ruta de Inicio Rápido</p><p>Si solo quieres comenzar rápidamente, puedes completar los pasos 1-4 de <a href="./provider-setup/">Configuración de Proveedores</a> (configurar Proveedores básicos), y aprender otros contenidos según sea necesario más adelante.</p></div><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><p>Antes de estudiar este capítulo, asegúrate de:</p><ul><li>✅ Haber completado <a href="./../installation/">Instalación y Configuración Inicial</a></li><li>✅ Tener instalado OpenCode (versión &gt;= 1.0.150)</li><li>✅ Comprender los formatos básicos de archivos de configuración JSON/JSONC</li><li>✅ Tener al menos una suscripción de cuenta de Proveedor de IA (se recomienda Anthropic Claude)</li></ul><div class="warning custom-block"><p class="custom-block-title">¿Qué pasa si no tengo una cuenta de Proveedor?</p><p>Puedes aprender los pasos de configuración primero sin conectar realmente un Proveedor. El sistema usará el modelo predeterminado de OpenCode como respaldo.</p></div><h2 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h2><details><summary><strong>¿Necesito configurar todos los Proveedores?</strong></summary><p>No. Puedes configurar solo los Proveedores que usas más (por ejemplo, solo Anthropic Claude). El mecanismo de conmutación de Proveedores de oh-my-opencode usará automáticamente los Proveedores disponibles.</p><p>Sin embargo, si quieres aprovechar completamente las ventajas de la orquestación multi-modelo, recomendamos configurar al menos 2-3 Proveedores, para que el sistema pueda seleccionar automáticamente el modelo más adecuado según el tipo de tarea.</p></details><details><summary><strong>¿Cuál es la diferencia entre configuración de Proveedores y resolución de modelos?</strong></summary><ul><li><strong>Configuración de Proveedores</strong>: El &quot;paso de instalación&quot;, indicando al sistema qué servicios de IA tienes disponibles</li><li><strong>Resolución de Modelos</strong>: La &quot;lógica de decisión&quot;, cómo el sistema selecciona qué Proveedor usar para cada agente</li></ul><p>Analogía: La configuración de Proveedores es &quot;contratar miembros del equipo&quot;, la resolución de modelos es &quot;asignar tareas&quot;.</p></details><details><summary><strong>¿Puedo modificar la configuración en cualquier momento?</strong></summary><p>Puedes modificar el archivo de configuración en cualquier momento:</p><ul><li>Configuración de usuario: <code>~/.config/opencode/oh-my-opencode.json</code></li><li>Configuración de proyecto: <code>.opencode/oh-my-opencode.json</code></li></ul><p>Los cambios surten efecto automáticamente la próxima vez que uses un agente. Si modificaste la autenticación del Proveedor, necesitas ejecutar <code>opencode auth login</code> para reautenticarte.</p></details><h2 id="proximos-pasos" tabindex="-1">Próximos Pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes:</p><h3 id="ruta-recomendada-aprender-el-equipo-de-agentes-de-ia" tabindex="-1">Ruta Recomendada: Aprender el Equipo de Agentes de IA <a class="header-anchor" href="#ruta-recomendada-aprender-el-equipo-de-agentes-de-ia" aria-label="Permalink to &quot;Ruta Recomendada: Aprender el Equipo de Agentes de IA&quot;">​</a></h3><p>Continúa aprendiendo <a href="./../../advanced/ai-agents-overview/">Equipo de Agentes de IA: Visión General de 10 Expertos</a> para comprender cómo usar diferentes agentes para tareas especializadas.</p><h3 id="ruta-avanzada-personalizacion-profunda" tabindex="-1">Ruta Avanzada: Personalización Profunda <a class="header-anchor" href="#ruta-avanzada-personalizacion-profunda" aria-label="Permalink to &quot;Ruta Avanzada: Personalización Profunda&quot;">​</a></h3><p>Si ya estás familiarizado con la configuración básica, puedes saltar a <a href="./../../advanced/advanced-configuration/">Profundización en Configuración: Gestión de Agentes y Permisos</a> para aprender:</p><ul><li>Cómo personalizar los prompts de los agentes</li><li>Cómo establecer permisos de agentes y ámbitos de acceso</li><li>Cómo crear agentes y Categorías personalizadas</li></ul><h3 id="ruta-practica-usar-planificacion-prometheus" tabindex="-1">Ruta Práctica: Usar Planificación Prometheus <a class="header-anchor" href="#ruta-practica-usar-planificacion-prometheus" aria-label="Permalink to &quot;Ruta Práctica: Usar Planificación Prometheus&quot;">​</a></h3><p>Comienza a usar <a href="./../../advanced/prometheus-planning/">Planificación Prometheus: Recopilación de Requisitos Estilo Entrevista</a> para experimentar el poder de la orquestación multi-modelo a través de la colaboración real de agentes.</p><hr><p><strong>Comienza</strong>: ¡Inicia tu viaje de orquestación multi-modelo con <a href="./provider-setup/">Configuración de Proveedores</a>!</p>`,42)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
